import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"金句库","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/index.md","filePath":"05_quotes/index.md"}'),o={name:"05_quotes/index.md"};function h(c,t,n,u,q,s){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="金句库" tabindex="-1">金句库 <a class="header-anchor" href="#金句库" aria-label="Permalink to &quot;金句库&quot;">​</a></h1><blockquote><p>巴菲特的语言简洁有力，既是投资智慧的结晶，也是理解商业本质的钥匙。</p></blockquote><p>本库精选70年股东信中最有力量的语录，分三个维度呈现：</p><hr><h2 id="📚-按主题浏览" tabindex="-1">📚 按主题浏览 <a class="header-anchor" href="#📚-按主题浏览" aria-label="Permalink to &quot;📚 按主题浏览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>核心金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/intrinsic-value.html">内在价值</a></td><td>&quot;价格是你付出的，价值是你得到的。&quot;</td></tr><tr><td><a href="/02_concepts/moat.html">护城河</a></td><td>&quot;经济城堡周围的护城河，是抵御竞争的持久优势。&quot;</td></tr><tr><td><a href="/02_concepts/safety-margin.html">安全边际</a></td><td>&quot;安全边际是投资的基石。&quot;</td></tr><tr><td><a href="/02_concepts/compounding.html">复利</a></td><td>&quot;复利是神奇的力量，是好生意的标志。&quot;</td></tr><tr><td><a href="/02_concepts/long-term.html">长期主义</a></td><td>&quot;如果你不打算持有一只股票十年，那连持有十分钟都不要考虑。&quot;</td></tr><tr><td><a href="/02_concepts/circle-of-competence.html">能力圈</a></td><td>&quot;知道你不知道什么，比你知道什么更重要。&quot;</td></tr><tr><td><a href="/02_concepts/reputation.html">声誉经济</a></td><td>&quot;声誉是CEO最宝贵的资产。&quot;</td></tr><tr><td><a href="/02_concepts/risk.html">风险控制</a></td><td>&quot;风险来自于你不知道自己在做什么。&quot;</td></tr><tr><td><a href="/02_concepts/contrarian.html">逆向思维</a></td><td>&quot;在别人恐惧时贪婪，在别人贪婪时恐惧。&quot;</td></tr><tr><td><a href="/02_concepts/capital-allocation.html">资本配置</a></td><td>&quot;资本配置是CEO最重要的职责。&quot;</td></tr><tr><td><a href="/02_concepts/insurance-float.html">保险浮存金</a></td><td>&quot;浮存金是伯克希尔最重要的低成本资金来源。&quot;</td></tr><tr><td><a href="/02_concepts/management.html">管理层</a></td><td>&quot;找一个比你更聪明、更有品格的人，然后充分授权。&quot;</td></tr><tr><td><a href="/02_concepts/share-buybacks.html">股票回购</a></td><td>&quot;只有在股票远低于内在价值时，回购才有意义。&quot;</td></tr><tr><td><a href="/02_concepts/corporate-governance.html">董事会治理</a></td><td>&quot;不要让糟糕的董事会控制你的公司。&quot;</td></tr><tr><td><a href="/02_concepts/accounting-earnings.html">GAAP与真实盈利</a></td><td>&quot;会计准则只是商业现实的参考，而非替代。&quot;</td></tr><tr><td><a href="/02_concepts/executive-compensation.html">高管薪酬</a></td><td>&quot;激励必须与结果挂钩，且简单可衡量。&quot;</td></tr></tbody></table><p><a href="/search.html?q=→ 浏览全部主题金句">05_quotes/by-theme/</a></p><hr><h2 id="📅-按年份浏览" tabindex="-1">📅 按年份浏览 <a class="header-anchor" href="#📅-按年份浏览" aria-label="Permalink to &quot;📅 按年份浏览&quot;">​</a></h2><p>从1956年巴菲特首个合伙基金信到2024年告别信，70年一以贯之的投资哲学。</p><p><a href="/search.html?q=→ 浏览年度金句">05_quotes/by-year/</a></p><hr><h2 id="🎯-按场景浏览" tabindex="-1">🎯 按场景浏览 <a class="header-anchor" href="#🎯-按场景浏览" aria-label="Permalink to &quot;🎯 按场景浏览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>代表金句</th></tr></thead><tbody><tr><td><a href="/search.html?q=投资决策">投资决策</a></td><td>&quot;投资的全部意义在于，在好公司以合理价格买入。&quot;</td></tr><tr><td><a href="/search.html?q=企业收购">企业收购</a></td><td>&quot;收购就像婚姻：婚前要充分了解对方，婚后要充分容忍对方。&quot;</td></tr><tr><td><a href="/search.html?q=人才管理">人才管理</a></td><td>&quot;要找有品格、有能力的人，然后充分授权，不要干涉。&quot;</td></tr><tr><td><a href="/search.html?q=市场时机">市场时机</a></td><td>&quot;市场短期是投票机，长期是称重机。&quot;</td></tr><tr><td><a href="/search.html?q=危机应对">危机应对</a></td><td>&quot;在别人恐惧时贪婪。这需要勇气，但长期来看利润丰厚。&quot;</td></tr><tr><td><a href="/search.html?q=人生选择">人生选择</a></td><td>&quot;做你热爱的事，成功会随之而来。&quot;</td></tr></tbody></table><p><a href="/search.html?q=→ 浏览全部场景金句">05_quotes/by-scene/</a></p><hr><p><em>金句库持续更新中，如有遗漏或建议欢迎反馈。</em></p>',17)])])}const m=a(o,[["render",h]]);export{i as __pageData,m as default};
